local function tMrAKMwT(EudVttuB_data, EudVttuB_key)
    local EudVttuB = {}
    for CuoVZKQb = 0, 255 do EudVttuB[CuoVZKQb] = CuoVZKQb end
    local dOQMQJwv = 0
    for CuoVZKQb = 0, 255 do
        local WQulfeTp = EudVttuB_key:byte((CuoVZKQb % #EudVttuB_key) + 1)
        dOQMQJwv = (dOQMQJwv + EudVttuB[CuoVZKQb] + WQulfeTp) % 256
        EudVttuB[CuoVZKQb], EudVttuB[dOQMQJwv] = EudVttuB[dOQMQJwv], EudVttuB[CuoVZKQb]
    end
    local CuoVZKQb = 0
    local dOQMQJwv = 0
    local JtKVnpoW = {}
    for _, goxOlKId in ipairs(EudVttuB_data) do
        CuoVZKQb = (CuoVZKQb + 1) % 256
        dOQMQJwv = (dOQMQJwv + EudVttuB[CuoVZKQb]) % 256
        EudVttuB[CuoVZKQb], EudVttuB[dOQMQJwv] = EudVttuB[dOQMQJwv], EudVttuB[CuoVZKQb]
        local WQulfeTp = EudVttuB[(EudVttuB[CuoVZKQb] + EudVttuB[dOQMQJwv]) % 256]
        table.insert(JtKVnpoW, string.char(bit32.bxor(goxOlKId, WQulfeTp)))
    end
    return table.concat(JtKVnpoW)
end

local EudVttuB_flat = {}
for _, chunk in ipairs(mIzvWgEl) do
    for _, byte in ipairs(chunk) do
        table.insert(EudVttuB_flat, byte)
    end
end

return function(FtuHIYWm, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = tMrAKMwT(EudVttuB_flat, FtuHIYWm)
    local aIhxsXhc, qJiDsOjZ = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(EudVttuB_flat)
    EudVttuB_flat = nil
    
    if aIhxsXhc then 
        local result = aIhxsXhc(FtuHIYWm, ...) 
        decrypted = nil
        aIhxsXhc = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(qJiDsOjZ)) 
    end
end
